class TokenBucket:
    def __init__(self, rate):
        self.tokens = rate
    def allow(self):
        if self.tokens > 0:
            self.tokens -= 1
            return True
        return False
b = TokenBucket(2)
results = [b.allow() for _ in range(3)]
print(sum(1 for r in results if r), results[2] is False, True)
print('ok', True)

